  ('fire-eq-eng-moex-00990', 'fire-eq-eng', 'fire-eq-eng-moex-099-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '關於展示用廣告板之防焰規定，下列敘述何者為誤？', '["展示用廣告板包括供舞台使用之大型道具合板", "展示用廣告板包括作為專櫃隔間使用之背板、隔間板及桌台等", "半永久性陳列之展示用廣告板不必列為防焰物品", "一般店舖以垂掛方式裝設之合板不必使用具防焰性能者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "558d9c38d998", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00991', 'fire-eq-eng', 'fire-eq-eng-moex-099-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '關於防焰性能試驗基準用語定義之敘述，下列何者為正確？', '["點火時間係指自火源點火接觸試樣起，至停止接觸之時間", "餘燃時間係指自點火時間終了起，至試樣停止燃燒之時間", "餘焰時間係指自點火時間終了起，試樣之火焰繼續燃燒之時間", "接焰次數係指試樣經接觸火源至完全收縮時之接觸火焰次數"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "558d9c38d998", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
